﻿@page "/"
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Home</PageTitle>

<div class="text-center py-5">
    <h1>📦 ShipmentTracker</h1>
    <p class="lead">Real-time shipment tracking for your logistics needs</p>
</div>

<div class="row justify-content-center">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track Your Shipment</h5>
                <p class="card-text">Enter your tracking number to see the current status of your shipment.</p>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="e.g. ST-A1B2C3D4"
                           @bind="trackingNumber" @bind:event="oninput"
                           @onkeydown="HandleKeyDown" />
                    <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                        Track
                    </button>
                </div>
            </div>
        </div>
    </div>
</div>

<AuthorizeView>
    <Authorized>
        <div class="text-center mt-4">
            <a href="/dashboard" class="btn btn-outline-secondary">
                📋 Go to Dispatcher Dashboard
            </a>
        </div>
    </Authorized>
</AuthorizeView>

@code {
    private string trackingNumber = string.Empty;

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            Navigation.NavigateTo($"/track/{trackingNumber.Trim()}");
        }
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            TrackShipment();
        }
    }
}

