+                        <td>
+                            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
+                        </td>
+                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+
+    @if (!FilteredShipments.Any())
+    {
+        <p class="text-muted">No shipments match your filter criteria.</p>
+    }
+}
+
+@code {
+    private List<ShipmentDto> shipments = new();
+    private bool loading = true;
+    private string? errorMessage;
+    private string searchText = string.Empty;
+    private string statusFilter = string.Empty;
+    private bool showNewForm;
+    private ShipmentDto newShipment = new();
+    private DateTime? estimatedDeliveryDate;
+    private string? formError;
+
+    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
+        (string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter) &&
+        (string.IsNullOrEmpty(searchText) ||
+         s.TrackingNumber.Contains(searchText, StringComparison.OrdinalIgnoreCase) ||
+         s.Origin.Contains(searchText, StringComparison.OrdinalIgnoreCase) ||
+         s.Destination.Contains(searchText, StringComparison.OrdinalIgnoreCase)));
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        try
+        {
+            loading = true;
+            shipments = await ShipmentService.GetAllShipmentsAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load shipments: {ex.Message}";
+        }
+        finally
+        {
+            loading = false;
+        }
+    }
+
+    private void ToggleNewForm()
+    {
+        showNewForm = !showNewForm;
+        if (showNewForm)
+        {
+            newShipment = new ShipmentDto();
+            estimatedDeliveryDate = null;
+            formError = null;
+        }
+    }
+
+    private async Task CreateShipment()
+    {
+        formError = null;
+
+        if (string.IsNullOrWhiteSpace(newShipment.Origin) || string.IsNullOrWhiteSpace(newShipment.Destination))
+        {
+            formError = "Origin and Destination are required.";
+            return;
+        }
+
+        newShipment.TrackingNumber = "ST-" + Guid.NewGuid().ToString("N")[..8].ToUpper();
+        newShipment.Status = "Pending";
+        newShipment.EstimatedDelivery = estimatedDeliveryDate.HasValue
+            ? DateTime.SpecifyKind(estimatedDeliveryDate.Value, DateTimeKind.Utc)
+            : null;
+
+        try
+        {
+            await ShipmentService.CreateShipmentAsync(newShipment);
+            showNewForm = false;
+            await LoadShipments();
+        }
+        catch (Exception ex)
+        {
+            formError = $"Failed to create shipment: {ex.Message}";
+        }
+    }
+
+    private static string GetStatusBadgeClass(string status) => status switch
+    {
+        "Pending" => "bg-secondary",
+        "InTransit" => "bg-primary",
+        "Delivered" => "bg-success",
+        "Delayed" => "bg-warning text-dark",
+        _ => "bg-light text-dark"
+    };
+}
